import { PageType } from 'lib/dot/enum/pageType';
import { DOTHelper } from 'lib/dot/DOTHelper';
import type { BooleanAnalytics } from 'lib/dot/types';
import type { TLocalityTypes } from 'utils/constants';
import { STATE, type TState } from 'utils/state';
import type { HomepageTab } from 'lib/dot/enum/homepageTab';

export type AnalyticsLocalityType = 'region' | 'district' | 'muni' | 'ward' | 'quarter' | 'street' | 'address' | '';

// This is always part of the analytics
export type FilterAnalyticsStatic = {
	action: 'filter';
	pageType: PageType;
	usedGoods: BooleanAnalytics;
	myProfile: BooleanAnalytics;
};

export type OfferStatusAnalytics = 'inactive' | 'active';

// Depending on filterName, the subsequent fields are different
export type FilterAnalyticsDynamic = { actionType: 'select' | 'deselect'; tab?: HomepageTab } & (
	| {
			filterName: 'locality';
			filterType: 'value';
			nearby: BooleanAnalytics;
			filterValue: string; // obsah text inputu
			localityType: AnalyticsLocalityType;
	  }
	| {
			filterName: 'locality';
			filterType: 'radius';
			filterValue: string; // radius
	  }
	| {
			filterName: 'price';
			filterType: 'price-range' | 'with-deal' | 'free';
			priceFrom?: number;
			priceTo?: number;
	  }
	| {
			filterName: 'status';
			filterValue: OfferStatusAnalytics;
	  }
	| { filterName: 'usedGoods' }
	| {
			filterName: 'status';
			filterType: 'expiring';
	  }
);

export type FilterAnalytics = FilterAnalyticsStatic & FilterAnalyticsDynamic;

// #if [DEV]
const FILTER_KEYS = ['pageType', 'usedGoods', 'myProfile'];
// #endif

export function sendFilterAnalytics(details: FilterAnalyticsDynamic) {
	// #if [DEV]
	DOTHelper.checkStore(FILTER_KEYS);
	// #endif

	const store = DOTHelper.getStore();

	if (details.filterName === 'usedGoods') {
		DOTHelper.addToStore({ usedGoods: DOTHelper.sanitizeBoolean(details.actionType === 'select') });
	}

	const data: FilterAnalytics = {
		action: 'filter',
		pageType: store.pageType,
		usedGoods: store.usedGoods,
		myProfile: store.myProfile,
		...details,
	};

	return DOTHelper.hit(data);
}

export function localityTypeToAnalyticsLocalityType(localityType: TLocalityTypes | ''): AnalyticsLocalityType {
	switch (localityType) {
		case '':
		case 'region':
		case 'address':
		case 'district':
		case 'ward':
		case 'quarter':
		case 'street':
			return localityType;
		case 'municipality':
			return 'muni';
	}
}

export function offerStatusToAnalyticsStatus(status: TState): OfferStatusAnalytics {
	if (status === STATE.ACTIVE) return 'active';
	return 'inactive';
}
