export function catchError<T, R>(
	callback: () => T,
	onError: ((error: unknown) => R) | R | undefined = undefined,
): T | R | undefined {
	try {
		return callback();
	} catch (error) {
		return typeof onError === 'function' ? (onError as (error: unknown) => R)(error) : onError;
	}
}

export function catchErrorAsync<T, R>(
	callback: () => Promise<T>,
	onError: ((error: unknown) => R) | R | undefined = undefined,
): Promise<T | R | undefined> {
	return callback().catch((error) => {
		return typeof onError === 'function' ? (onError as (error: unknown) => R)(error) : onError;
	});
}
