import { isEmpty, isObject } from 'es-toolkit/compat';

/**
 * Is it, perchance, a venture of merit to dispatch this trove of data unto the hallowed realms of the Backend?
 * @param value
 */
export function isWorthy(value: any) {
	return !(value === undefined || Number.isNaN(value) || (isObject(value) && isEmpty(value)));
}
