export type FilterSignalData = URLFilterParams & {
	fromQuery?: boolean;
	isAdmin?: boolean;
	isBazarek?: boolean;
	expiring: { value: 1 | undefined };
	limit: number;
	resolvedLocality?: LocalityData;
	seller?: UserData | PremiseData;
	shop?: ShopData;
	timestampTo: number;
};

const UNPACKED_SHOP_SORT_MAP = new Map<TSortBySort, undefined | TUnpackedOffersSort>([
	['-create_date', undefined],
	['-price', 'priceDesc'],
	['price', 'priceAsc'],
] as const);

export const DEFAULT_FILTER_VALUES = {
	category: CATEGORY_ALL_CATEGORIES,
	dohodou: { seoName: undefined },
	expiring: { value: undefined },
	hledej: { seoName: undefined },
	kde: { seoName: undefined },
	locality: LOCALITY_CELA_CR,
	page: { seoName: '', value: 0 },
	price: { from: undefined, seoName: 'cena-neomezena', type: 'cena-neomezena', to: undefined },
	radius: { seoName: undefined },
	sort: { seoName: 'nejnovejsi', sort: '-create_date' },
	watchdog_hash: { seoName: undefined },
	watchdog_id: { seoName: undefined },
	watchdog_timestamp: { seoName: undefined },
	limit: OFFERS_WITHOUT_ADS_PER_PAGE,
	status: { seoName: 'active', value: STATE.ACTIVE },
	rozbalene: { seoName: undefined },
	seller: undefined,
} as const;

export class FilterSignal extends Signal<FilterSignalData> {
	// Always construct with full data structure but empty/default values to make components dependent on this signal
	// work even without explicit filter initialization
	constructor() {
		super(FilterSignal.createDefaultFilter());
	}

	duplicate() {
		const newFilterSignal = new FilterSignal();
		newFilterSignal.value = structuredClone(this.peek());

		return newFilterSignal;
	}

	static checkIfErrorPage() {
		return Boolean(globalThis?.document?.getElementById('errorStatus'));
	}

	static createDefaultFilter(limit: number = OFFERS_WITHOUT_ADS_PER_PAGE): FilterSignalData {
		return {
			...structuredClone(DEFAULT_FILTER_VALUES),
			timestampTo: roundedTimestamp(),
			limit,
		};
	}

	// This init is used for server side mainly
	static async init(url: URL, user: Promise<UserData | null> | UserData | null): Promise<FilterSignalData> {
		const limit =
			url.pathname === '/'
				? TAB_OFFERS_PER_PAGE
				: url.pathname.includes('ulozene-nabidky')
					? OFFERS_PER_PAGE
					: OFFERS_WITHOUT_ADS_PER_PAGE;
		const filter: FilterSignalData = FilterSignal.createDefaultFilter(limit);

		if (FilterSignal.checkIfErrorPage()) return filter;

		const urlResolvedFilter = {
			...filter,
			...catchError(
				() => (isUrlQueryDecoderNeeded(url) ? urlQueryDecoder(url) : urlDecoder(url)),
				(error) => {
					if (isSSR()) throw error;
					return undefined;
				},
			),
			isBazarek: isBazarekUrl(url),
		};

		const [sellerFilter, resolvedLocality] = await Promise.all([
			catchErrorAsync(() => getSellerOrShopFromUrl(url, user), undefined),
			urlResolvedFilter.locality.id && !urlResolvedFilter.locality.name
				? resolveLocality({
						entity_id: urlResolvedFilter.locality.id,
						entity_type: urlResolvedFilter.locality.type,
					})
						.then((locality) => ({ ...locality, name: getLocalityName(locality) }))
						.catch(() => {
							if (isSSR()) {
								throw new KnownLocalityNotFoundError(
									`Failed searching: { id: ${urlResolvedFilter.locality.id}, type: ${urlResolvedFilter.locality.type} }`,
								);
							}
							return undefined;
						})
				: undefined,
		]);

		return {
			...urlResolvedFilter,
			...sellerFilter,
			resolvedLocality,
			locality:
				!urlResolvedFilter.locality?.name && !resolvedLocality
					? LOCALITY_CELA_CR
					: resolvedLocality
						? {
								...urlResolvedFilter.locality,
								name: resolvedLocality.name,
							}
						: urlResolvedFilter.locality,
		};
	}

	// This init is used for client side only
	async init(url: URL) {
		this.value = await FilterSignal.init(url, null);

		return this.value;
	}

	generateUrl({
		filterParams = {},
		defaultPath,
		placement,
	}: {
		filterParams?: Partial<URLFilterParams>;
		defaultPath?: string;
		placement?: [TParamKeys, boolean][] | false;
	}) {
		return urlEncoder(
			this.getUpdatedValue(filterParams, {
				resetPagination: false,
				resetWatchdog: false,
			}),
			placement,
			defaultPath,
		);
	}

	historyPushState(placement?: [TParamKeys, boolean][], defaultPath?: string, searchType?: SearchType) {
		const { seller, shop } = this.peek();
		const data = { searchType, spa: true };

		const title = META.getTitleFromFilterSignal(filters.peek());
		if (title) {
			META.setTitle(title);
		}

		if (seller === undefined && shop === undefined) {
			navigateSPA(this.generateUrl({ defaultPath, placement }), data);
			return;
		}

		navigateSPA(
			this.generateUrl({
				defaultPath: globalThis.window.location.pathname,
				placement: shop || seller ? false : placement,
			}),
			data,
		);
	}

	localFilterToRemote(limit = this.peek().limit): RemoteFilter {
		const filter = this.peek();

		return localFilterToRemote(filter, limit);
	}

	/**
	 * @param radius
	 * @param analytics
	 */
	updateRadius(radius: number, analytics: boolean = true) {
		this.updateValue({
			radius: {
				seoName: radius === DEFAULT_RADIUS_VALUE ? undefined : radius.toString(),
			},
		});

		if (analytics) {
			sendFilterAnalytics({
				filterName: 'locality',
				filterType: 'radius',
				actionType: 'select',
				filterValue: radius.toString(),
			});
		}
	}

	updateLocality(locality: LocalityData, nearby: boolean) {
		this.updateValue({
			locality: localityToFilterLocality(locality),
			kde: {
				seoName: getKdeParameter(locality),
			},
			resolvedLocality: locality,
		});

		sendFilterAnalytics({
			filterName: 'locality',
			filterType: 'value',
			actionType: 'select',
			filterValue: getLocalityName(locality),
			localityType: localityTypeToAnalyticsLocalityType(locality.entityType),
			nearby: DOTHelper.sanitizeBoolean(nearby),
		});
	}

	updateLocalityFromSuggest(locality: LocalitySuggestionData, sendDeselectAnalytics?: boolean) {
		const knownLocality = getKnownLocalityByLocality(locality);
		const resolvedLocality = this.peek().resolvedLocality;

		if (sendDeselectAnalytics) {
			sendFilterAnalytics({
				filterName: 'locality',
				filterType: 'value',
				actionType: 'deselect',
				filterValue: resolvedLocality ? getLocalityName(resolvedLocality) : this.peek().locality.name,
				localityType: localityTypeToAnalyticsLocalityType(
					resolvedLocality?.entityType ?? this.peek().locality.type,
				),
				nearby: 0,
			});
		}

		this.updateValue({
			locality: {
				id: locality.entityId,
				type:
					Object.values(LOCALITY_TYPES).find((type) => type === locality.entityType) ||
					LOCALITY_TYPES.ADDRESS,
				name: knownLocality ? knownLocality.name : locality.suggestFirstRow,
				seoName: knownLocality ? knownLocality.seoName : locality.seoName,
			},
			kde: {
				seoName: getKdeParameter(locality),
			},
			resolvedLocality: undefined,
		});
	}

	updateSorting(sort: TSortBySort) {
		this.updateValue(
			{
				sort: {
					sort,
					seoName: SORT_BY_SEO_NAMES[SORT_KEYS_BY_SORT[sort]],
				},
			},
			{ resetWatchdog: false },
		);
	}

	/**
	 *
	 * @param from
	 * @param to
	 * @param type
	 * @param analyticsOptions With the other filters, updating them implies a refresh and triggering analytics.
	 * However, there is an edge case with price where update to a price should not immediately trigger
	 * a page refresh, unlike all the other filters. Instead, the refresh should trigger when clicking away/pressing
	 * enter. However, even when we do not trigger refresh, we need to update the filter.
	 */
	updatePrice({ from, to, type }: PriceChange, analyticsOptions: { source: PriceChangeReason } | false) {
		this.updateValue({
			...this.getPrice({ from, to, type }),
			...(type == PRICE.FREE && {
				rozbalene: {
					seoName: undefined,
				},
			}),
		});

		if (analyticsOptions) {
			if (analyticsOptions.source === 'free') {
				sendFilterAnalytics({
					filterName: 'price',
					filterType: 'free',
					actionType: type === PRICE.FREE ? 'select' : 'deselect',
				});
			} else {
				sendFilterAnalytics({
					filterName: 'price',
					filterType: 'price-range',
					actionType: from || to ? 'select' : 'deselect',
					priceFrom: from,
					priceTo: to,
				});
			}
		}
	}

	private getPrice({ from, to, type }: PriceChange) {
		return {
			price: {
				from,
				to,
				type,
				seoName: getPriceSeoName(from, to, type),
			},
		};
	}

	updateAgreement(value: boolean) {
		this.updateValue({
			dohodou: {
				seoName: value ? undefined : 'bez',
			},
			rozbalene: {
				seoName: undefined,
			},
		});

		sendFilterAnalytics({
			filterName: 'price',
			filterType: 'with-deal',
			actionType: value ? 'select' : 'deselect',
		});
	}

	updateUnpacked(value: boolean) {
		this.updateValue({
			rozbalene: {
				seoName: value ? 'ano' : undefined,
			},
			...(value && this.peek().price.type === PRICE.FREE && this.getPrice({ type: PRICE.NO_LIMIT })),
			...(value && { dohodou: { seoName: 'bez' } }),
		});

		sendFilterAnalytics({
			filterName: 'usedGoods',
			actionType: value ? 'select' : 'deselect',
		});
	}

	updateStatus(status: TState) {
		this.updateValue({
			status: {
				value: status,
				seoName: status === STATE.ACTIVE ? 'active' : 'inactive',
			},
			category: CATEGORY_ALL_CATEGORIES,
		});

		if (status === STATE.INACTIVE) this.updateExpiring(false, false);

		sendFilterAnalytics({
			filterName: 'status',
			actionType: 'select',
			filterValue: offerStatusToAnalyticsStatus(status),
		});
	}

	updateExpiring(expiring: boolean, measureAnalytics: boolean = true) {
		this.updateValue({
			expiring: {
				value: expiring ? UPCOMING_EXPIRING_URL_VALUE : undefined,
			},
		});

		if (measureAnalytics) {
			sendFilterAnalytics({
				filterName: 'status',
				filterType: 'expiring',
				actionType: expiring ? 'select' : 'deselect',
			});
		}
	}

	updateCategory(category: CategoryData) {
		this.updateValue({ category });
	}

	getUpdatedValue(
		valueUpdates: Partial<FilterSignalData>,
		{
			resetWatchdog = true,
			resetPagination = true,
		}: {
			resetWatchdog?: boolean;
			resetPagination?: boolean;
		} = {},
	): FilterSignalData {
		const newValue = {
			...this.peek(),
		};

		if (resetPagination) {
			newValue.page = { value: 1, seoName: '1' };
		}

		if (resetWatchdog) {
			newValue.watchdog_hash = undefined;
			newValue.watchdog_id = undefined;
			newValue.watchdog_timestamp = undefined;
		}

		return {
			...newValue,
			...valueUpdates,
		};
	}

	private updateValue(
		valueUpdates: Partial<FilterSignalData>,
		{
			resetWatchdog = true,
			resetPagination = true,
		}: {
			resetWatchdog?: boolean;
			resetPagination?: boolean;
		} = {},
	) {
		this.value = this.getUpdatedValue(valueUpdates, { resetWatchdog, resetPagination });
	}

	isPriceDifferent(price: PriceChange): boolean {
		const { from, to, type } = this.peek().price;
		return from !== price.from || to !== price.to || type !== price.type;
	}

	/**
	 * Resets only the filters that are adjustable by the user in the FilterPanel component (i.e. does not reset phrase,
	 * category, etc.)
	 */
	resetPanelFilters() {
		this.updateValue({
			locality: LOCALITY_CELA_CR,
			dohodou: DEFAULT_FILTER_VALUES.dohodou,
			kde: DEFAULT_FILTER_VALUES.kde,
			price: DEFAULT_FILTER_VALUES.price,
			radius: DEFAULT_FILTER_VALUES.radius,
			rozbalene: DEFAULT_FILTER_VALUES.rozbalene,
			expiring: DEFAULT_FILTER_VALUES.expiring,
		});
	}

	arePanelFiltersDefault() {
		const { locality, dohodou, kde, price, rozbalene, expiring } = this.peek();
		return (
			locality.id === LOCALITY_CELA_CR.id &&
			(!dohodou?.seoName || dohodou?.seoName !== 'bez') &&
			!kde?.seoName &&
			(price.from === undefined || price.from === 0) &&
			(price.to === undefined || price.to === 0) &&
			price.type === DEFAULT_FILTER_VALUES.price.type &&
			!rozbalene?.seoName &&
			!expiring?.value
		);
	}
}

const startsQueryUrls = [
	'/bazar/',
	'/eshop-rozbalene/',
	'/sauto/',
	'/500',
	'/404',
	'/error/500',
	'/error/503',
	'/error/404',
	'/ulozene-nabidky',
	'/ulozena-hledani',
	'/inzerat',
	'/rozbalena-nabidka',
	'/nova-nabidka',
];

function isUrlQueryDecoderNeeded(url: URL): boolean {
	return (
		startsQueryUrls.some((queryUrl) => url.pathname.startsWith(queryUrl)) || url.pathname.split('/')[2] === 'detail'
	);
}

function isBazarekUrl(url: URL): boolean {
	return (
		url.pathname.startsWith('/bazar/') ||
		url.pathname.startsWith('/sauto/') ||
		url.pathname.startsWith('/eshop-rozbalene/')
	);
}

function getSellerOrShopFromUrl(
	url: URL,
	user?: Promise<UserData | null> | UserData | null,
): Promise<
	{ seller: UserData | PremiseData | undefined; isAdmin?: boolean } | { shop: ShopData | undefined } | undefined
> {
	const [_, firstSlug, secondSlug] = url.pathname.split('/');
	if (!firstSlug) return Promise.resolve(undefined);

	// format: /sauto/{premiseId}-{seoName}
	if (firstSlug === 'sauto' && secondSlug) {
		const premiseId = secondSlug.split('-')[0];

		if (premiseId) {
			return getPremiseSeller(premiseId).then((seller) => {
				return { seller };
			});
		}
		return Promise.resolve(undefined);
	}
	// format: /eshop-rozbalene/{shopSeo}
	if (firstSlug === 'eshop-rozbalene') {
		if (secondSlug) {
			return getShop({ id: secondSlug }).then((shop) => {
				return { shop };
			});
		}
		return Promise.resolve(undefined);
	}

	// format: /bazar/{bazarSeo}
	// old format: /{bazarSeo} is not supported
	if (firstSlug !== 'bazar' || !secondSlug) return Promise.resolve(undefined);
	return Promise.all([
		catchErrorAsync(() => getUserByShopUrl({ shop_url: secondSlug }), undefined),
		user ||
			(globalThis?.window?.login?.current?.state === 'login'
				? {
						uid: globalThis?.window?.login?.current?.uid,
						state: globalThis?.window?.login?.current?.state,
					}
				: getUserSelf({}).catch(() => null)),
	]).then(([seller, user]) => {
		return {
			seller,
			isAdmin: !!user && ('id' in user ? user.id === seller?.id : user.uid === seller?.id),
		};
	});
}

export const filters = new FilterSignal();
export const filtersPanelOpened = new CookieBooleanSignal(true, FILTERS_PANEL_OPENED_COOKIE);

export function hideFiltersPanel() {
	filtersPanelOpened.value = false;
}

export function openFiltersPanel() {
	filtersPanelOpened.value = true;
}

// Sometimes, a page will receive new filters from the SSR. We cannot use astro:after-swap because the SSR filters have priority.
globalThis?.document?.addEventListener('astro:after-swap', () => {
	filters.init(new URL(globalThis.window.location.href));
});

export function getCategoriesSort(filter: FilterSignalData) {
	return filter.hledej.seoName ? '-adverts_count' : 'name';
}

export function localFilterToModalWatchdogFilter(filter: URLFilterParams): ModalWatchdogDataFilter {
	return pickBy(
		{
			phrase: filter.hledej?.seoName,
			price_from: filter.price?.from,
			price_to: filter.price?.to,
			locality: filter.locality,
			radius_precision: filter.locality.id
				? ((filter.radius?.seoName && Number(filter.radius?.seoName)) ?? DEFAULT_RADIUS_VALUE)
				: undefined,
			category_id: filter.category?.id,
			hide_price_by_agreement: filter.dohodou?.seoName === 'bez',
			price_for_free: filter.price?.type === 'zdarma',
		},
		isWorthy,
	);
}

export function getSortRemoteParameter(filter: FilterSignalData): undefined | TRemoteSort {
	const route = getRouteFromFilters(filter);

	if (route === 'unpacked_bazar' || route === 'unpacked_search') {
		return UNPACKED_SHOP_SORT_MAP.get(filter.sort?.sort);
	}

	if (route === 'sauto_bazar' && filter.sort.sort === '-create_date') {
		return '-timestamp';
	}

	if (route === 'user_bazar') {
		if (filter.status?.value === 'active' && filter.sort?.sort === '-create_date') {
			return '-edit_date';
		}

		if (filter.status?.value === 'inactive,disabled' && filter.sort?.sort === '-create_date') {
			return '-admin_rejected,-deactivation_date';
		}
	}

	// watchdog has legit sort parameter as `-create_date` to show label "new" offers first
	if (route === 'search' && filter.sort?.sort === '-create_date' && filter.watchdog_id?.seoName) {
		return '-create_date';
	}

	if (route === 'search' && filter.sort?.sort === '-create_date') {
		return undefined;
	}

	return filter.sort?.sort;
}

export function localFilterToRemote(filter: FilterSignalData, limit = OFFERS_WITHOUT_ADS_PER_PAGE): RemoteFilter {
	assert(limit, 'Limit must be set in the filter.');

	const loadedWatchdogIdInPast = offers.peek().watchdogId;
	const isInitialWatchdogRequest =
		loadedWatchdogIdInPast === undefined || loadedWatchdogIdInPast !== filter.watchdog_id?.seoName;

	const filtersLocality = filter.locality && filter.locality?.type !== 'address' && filter.locality.id !== 0;
	return pickBy(
		{
			premise_id: filter.seller?.isPremise ? filter.seller?.id : undefined,
			user_id: filter.isBazarek && !filter.seller?.isPremise ? filter.seller?.id : undefined,
			category_id: filter.category?.id,
			hide_price_by_agreement: filter.dohodou?.seoName === 'bez' ? 'true' : undefined,
			limit,
			locality: filtersLocality ? `${filter.locality?.type},${filter.locality?.id}` : undefined,
			offset: filter.page?.value && limit * (filter.page?.value - 1),
			phrase: filter.hledej?.seoName,
			price_for_free: filter.price?.type === 'zdarma' ? 'true' : undefined,
			price_from: filter.price?.from,
			price_to: filter.price?.to,
			radius_precision: filter.radius?.seoName
				? String(filter.radius?.seoName)
				: filtersLocality
					? String(DEFAULT_RADIUS_VALUE)
					: undefined,
			sort: getSortRemoteParameter(filter),
			timestamp_to: filter.isBazarek ? undefined : filter.timestampTo,
			watchdog_id: isInitialWatchdogRequest ? Number(filter.watchdog_id?.seoName) : undefined,
			watchdog_hash: isInitialWatchdogRequest ? filter.watchdog_hash?.seoName : undefined,
			status: filter.isAdmin ? filter.status?.value : undefined,
			shop_id: filter.shop?.id ?? undefined,
			valid_date_to: filter.expiring?.value ? getISOStringDate(UPCOMING_EXPIRING_DAYS) : undefined,
		},
		isWorthy,
	);
}

function getISOStringDate(days: number | undefined = 0) {
	const today = new Date();
	const DAY_IN_MS = 24 * 60 * 60 * 1000;
	const date = new Date(today.getTime() + days * DAY_IN_MS);
	return date.toISOString().split('T')[0];
}

export function localityToFilterLocality(locality: LocalityData): TLocality {
	return {
		id: locality.entityId,
		type: locality.entityType,
		seoName: getLocalitySeoName(locality),
		name: getLocalityName(locality),
	};
}

export function localitySuggestionToFilterLocality(locality: LocalitySuggestionData): TLocality {
	return {
		id: locality.entityId,
		type: locality.entityType,
		seoName: locality.seoName,
		name: locality.suggestFirstRow,
	};
}

export type RemoteFilter = {
	category_id?: string;
	hide_price_by_agreement?: 'true' | 'false';
	include_adverts_stats?: 1;
	limit?: string;
	locality?: string;
	offset?: string;
	phrase?: string;
	premise_id?: string;
	price_for_free?: 'true' | 'false';
	price_from?: string;
	price_to?: string;
	radius_precision?: string;
	shop_id?: string;
	sort?: TRemoteSort;
	status?: TState;
	timestamp_to?: string;
	user_id?: string;
	watchdog_hash?: string;
	watchdog_id?: string;
	watchdog_timestamp?: number;
	valid_date_from?: string;
	valid_date_to?: string;
};

export function remoteFilterToSearchCategoriesParams(filter: RemoteFilter, sort?: SortBy): SearchCategoriesParams {
	const newFilter: SearchCategoriesParams = {
		category_id: filter.category_id,
		hide_price_by_agreement: filter.hide_price_by_agreement,
		limit: filter.limit,
		locality: filter.locality,
		offset: filter.offset,
		phrase: filter.phrase,
		premise_id: filter.premise_id,
		price_for_free: filter.price_for_free,
		price_from: filter.price_from,
		price_to: filter.price_to,
		radius_precision: filter.radius_precision,
		sort: sort,
		timestamp_to: filter.timestamp_to,
		user_id: filter.user_id,
	};

	return pickBy(newFilter, isWorthy);
}

export function remoteFilterToSearchUserCategoriesParams(
	filter: RemoteFilter,
	sort?: SortBy,
): SearchUserCategoriesParams {
	const newFilter: SearchUserCategoriesParams = {
		advert_locality: filter.locality,
		advert_price_for_free: filter.price_for_free,
		advert_price_from: filter.price_from,
		advert_price_to: filter.price_to,
		advert_status: filter.status ?? 'active',
		advert_valid_date_from: filter.valid_date_from,
		advert_valid_date_to: filter.valid_date_to,
		limit: filter.limit,
		offset: filter.offset,
		radius_precision: filter.radius_precision,
		sort: sort,
	};

	return pickBy(newFilter, isWorthy);
}

export function getFilterSeoNames(filter: FilterSignalData) {
	return {
		hledej: filter.hledej?.seoName,
		category: filter.category?.seoName,
		locality: filter.locality?.seoName,
		price: filter.price?.seoName,
		sort: filter.sort?.seoName,
		radius: filter.radius?.seoName,
		page: filter.page?.seoName,
		status: filter.status,
		timestampTo: filter.timestampTo,
		watchdog_hash: filter.watchdog_hash?.seoName,
		watchdog_id: filter.watchdog_id?.seoName,
		watchdog_timestamp: filter.watchdog_timestamp?.seoName,
		limit: filter.limit,
		isBazarek: filter.isBazarek,
		isAdmin: filter.isAdmin,
		fromQuery: filter.fromQuery,
		shop: filter.shop?.seoName,
		seller: filter.seller?.isPremise ? filter.seller?.seoName : filter.seller?.userService.shopUrl,
		rozbalene: filter.rozbalene?.seoName,
		dohodou: filter.dohodou?.seoName,
	};
}
