import { createAPIMethod } from 'utils/generic';
import type { PremiseData } from './model';
import { normalizeOfferPremiseData } from './model';

export async function getPremiseSeller(premiseId: string, headers?: HeadersInit) {
	return createAPIMethod<object, PremiseData>({
		method: 'GET',
		path: `/premises/public/${premiseId}`,
		normalize: ({ result }) => normalizeOfferPremiseData(result),
		useCache: true,
		headers,
	})();
}
